module top_module(
    input      clk,
    input      rst,
    input      pulse,
    output reg toggle
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge rst or posedge dbg_halt)
        if (rst)
            toggle <= 0;
        else
            toggle <= toggle ^ pulse;

endmodule
